<template>
  <div class="source-code-manager">
    <el-page-header title="返回" @back="goBack">
      <template #content>
        <h2>源代码管理</h2>
      </template>
      <template #extra>
        <el-button type="primary" @click="showUploadDialog">
          <el-icon><Upload /></el-icon> 上传源代码
        </el-button>
      </template>
    </el-page-header>

    <el-card class="filter-card">
      <el-form :inline="true" :model="filterForm">
        <el-form-item label="搜索项目">
          <el-input v-model="filterForm.keyword" placeholder="输入项目名称"></el-input>
        </el-form-item>
        <el-form-item label="语言">
          <el-select v-model="filterForm.language" placeholder="所有语言">
            <el-option label="Java" value="Java"></el-option>
            <el-option label="Python" value="Python"></el-option>
            <el-option label="C++" value="C++"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="状态">
          <el-select v-model="filterForm.status" placeholder="所有状态">
            <el-option label="已分析" value="analyzed"></el-option>
            <el-option label="未分析" value="unanalyzed"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="searchProjects">搜索</el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <el-card>
      <template #header>
        <div class="card-header">
          <span>源代码项目列表</span>
          <div>
            <el-tag type="info">总计: {{ projects.length }}</el-tag>
            <el-tag type="success">已分析: {{ analyzedCount }}</el-tag>
            <el-tag type="warning">未分析: {{ unanalyzedCount }}</el-tag>
          </div>
        </div>
      </template>

      <el-table :data="filteredProjects" style="width: 100%">
        <el-table-column prop="name" label="项目名称"></el-table-column>
        <el-table-column prop="language" label="语言">
          <template #default="{ row }">
            <el-tag :type="row.language === 'Java' ? '' : 'info'">
              {{ row.language }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="size" label="大小"></el-table-column>
        <el-table-column prop="uploadTime" label="上传时间"></el-table-column>
        <el-table-column prop="status" label="状态">
          <template #default="{ row }">
            <el-tag :type="row.status === 'analyzed' ? 'success' : 'warning'">
              {{ row.status === 'analyzed' ? '已分析' : '未分析' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="200">
          <template #default="{ row }">
            <el-button size="small" @click="viewProject(row)">查看</el-button>
            <el-button size="small" type="primary" @click="runAnalysis(row)">运行</el-button>
          </template>
        </el-table-column>
      </el-table>

      <el-pagination
        class="pagination"
        v-model:current-page="currentPage"
        v-model:page-size="pageSize"
        :page-sizes="[10, 20, 30, 50]"
        layout="total, sizes, prev, pager, next, jumper"
        :total="projects.length"
      />
    </el-card>

    <!-- 上传对话框 -->
    <el-dialog v-model="uploadDialogVisible" title="上传源代码" width="50%">
      <el-upload
        class="upload-demo"
        drag
        action="https://jsonplaceholder.typicode.com/posts/"
        multiple
        :on-change="handleFileChange"
      >
        <el-icon class="el-icon--upload"><upload-filled /></el-icon>
        <div class="el-upload__text">拖放文件到此处或<em>点击上传</em></div>
        <template #tip>
          <div class="el-upload__tip">支持 .zip, .jar, .java, .py 等格式</div>
        </template>
      </el-upload>

      <el-form :model="uploadForm" label-width="100px">
        <el-form-item label="项目名称">
          <el-input v-model="uploadForm.name"></el-input>
        </el-form-item>
        <el-form-item label="项目描述">
          <el-input v-model="uploadForm.description" type="textarea"></el-input>
        </el-form-item>
        <el-form-item label="编程语言">
          <el-select v-model="uploadForm.language" placeholder="请选择">
            <el-option label="Java" value="Java"></el-option>
            <el-option label="Python" value="Python"></el-option>
            <el-option label="C++" value="C++"></el-option>
          </el-select>
        </el-form-item>
      </el-form>

      <template #footer>
        <span class="dialog-footer">
          <el-button @click="uploadDialogVisible = false">取消</el-button>
          <el-button type="primary" @click="submitUpload">上传</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'
import { useRouter } from 'vue-router'
import { useStore } from 'vuex'
import { UploadFilled } from '@element-plus/icons-vue'

const router = useRouter()
const store = useStore()

const filterForm = ref({
  keyword: '',
  language: '',
  status: ''
})

const currentPage = ref(1)
const pageSize = ref(10)

const uploadDialogVisible = ref(false)
const uploadForm = ref({
  name: '',
  description: '',
  language: ''
})

const projects = computed(() => store.state.projects)

const analyzedCount = computed(() => 
  projects.value.filter(p => p.status === 'analyzed').length
)

const unanalyzedCount = computed(() => 
  projects.value.filter(p => p.status !== 'analyzed').length
)

const filteredProjects = computed(() => {
  return projects.value.filter(project => {
    const matchesKeyword = project.name.includes(filterForm.value.keyword)
    const matchesLanguage = filterForm.value.language ? 
      project.language === filterForm.value.language : true
    const matchesStatus = filterForm.value.status ? 
      project.status === filterForm.value.status : true
    return matchesKeyword && matchesLanguage && matchesStatus
  })
})

function goBack() {
  router.go(-1)
}

function showUploadDialog() {
  uploadDialogVisible.value = true
}

function handleFileChange(file, fileList) {
  console.log(file, fileList)
}

function submitUpload() {
  const newProject = {
    id: projects.value.length + 1,
    name: uploadForm.value.name,
    language: uploadForm.value.language,
    size: '0 MB',
    uploadTime: new Date().toLocaleString(),
    status: 'unanalyzed'
  }
  store.commit('addProject', newProject)
  uploadDialogVisible.value = false
  uploadForm.value = { name: '', description: '', language: '' }
}

function viewProject(project) {
  console.log('View project:', project)
  // 实际项目中这里会导航到项目详情页
}

function runAnalysis(project) {
  console.log('Run analysis for:', project)
  // 调用API运行分析
}

function searchProjects() {
  console.log('Search with:', filterForm.value)
}
</script>

<style scoped>
.source-code-manager {
  padding: 20px;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.filter-card {
  margin-bottom: 20px;
}

.pagination {
  margin-top: 20px;
  justify-content: center;
}

.upload-demo {
  text-align: center;
  margin-bottom: 20px;
}
</style>